import { Link } from 'react-router-dom';
import { Instagram, Linkedin, Youtube, Facebook, Twitter } from 'lucide-react';
import { BRAND } from '@/lib/brand';
import { FOOTER_GROUPS, findMenuPage, routeForSlug } from '@/data/megaMenu';

const YEAR = new Date().getFullYear();

const SOCIALS = [
  { label: 'Instagram', Icon: Instagram, href: '#' },
  { label: 'LinkedIn', Icon: Linkedin, href: '#' },
  { label: 'Facebook', Icon: Facebook, href: '#' },
  { label: 'X', Icon: Twitter, href: '#' },
] as const;

export function SiteFooter() {
  return (
    <footer className="border-t border-white/[0.06] bg-background text-white">
      <div className="mx-auto max-w-7xl px-6 pb-12 pt-20">
        
        {/* Top Section: Logo & Columns */}
        <div className="grid gap-14 lg:grid-cols-12">
          
          {/* Logo & Brand (Left Column) */}
          <div className="lg:col-span-3">
            <div className="flex items-center gap-3">
              <img 
                src="/logo.png" 
                alt="Logo Rei das Vendas" 
                className="h-12 w-auto object-contain"
              />
            </div>
            <p className="mt-8 max-w-xs text-xs leading-relaxed text-white/40">
              Somos a infraestrutura de engenharia digital para operações de alta performance.
            </p>
          </div>

          {/* Links Columns (Right Columns) */}
          <div className="lg:col-span-9 grid grid-cols-2 gap-x-8 gap-y-12 sm:grid-cols-3 md:grid-cols-5">
            {FOOTER_GROUPS.map((group) => (
              <div key={group.title}>
                <p className="text-[11px] font-semibold text-white/90">
                  {group.title}
                </p>
                <ul className="mt-6 grid gap-4">
                  {group.slugs.map((slug) => {
                    const page = findMenuPage(slug);
                    if (!page) return null;
                    const href = routeForSlug(slug) || '#';
                    return (
                      <li key={slug}>
                        <Link
                          to={href}
                          className="text-[12px] text-white/50 transition-colors hover:text-white"
                        >
                          {page.title}
                        </Link>
                      </li>
                    );
                  })}
                </ul>

                {/* Se for a coluna Empresa, adiciona as redes sociais no final */}
                {group.title === 'Empresa' && (
                  <div className="mt-10">
                    <p className="text-[11px] font-semibold text-white/90">Siga</p>
                    <ul className="mt-6 grid gap-4">
                      {SOCIALS.map(({ href, label }) => (
                        <li key={label}>
                          <a
                            href={href}
                            className="text-[12px] text-white/50 transition-colors hover:text-white"
                          >
                            {label}
                          </a>
                        </li>
                      ))}
                    </ul>
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>

        {/* Bottom Section: Copyright & Legal */}
        <div className="mt-24 flex flex-col gap-6 md:flex-row md:items-center md:justify-between">
          <div className="flex items-center gap-4">
            <span className="text-[11px] text-white/40">
              &copy; {YEAR} {BRAND.name}. Todos os direitos reservados.
            </span>
          </div>
          <nav
            aria-label="Rodapé"
            className="flex flex-wrap gap-x-6 gap-y-2 text-[11px] text-white/40"
          >
            <Link className="hover:text-white transition-colors" to="/termos">Termos</Link>
            <Link className="hover:text-white transition-colors" to="/politica">Privacidade</Link>
            <Link className="hover:text-white transition-colors" to="/politica">Preferências de Cookies</Link>
            <Link className="hover:text-white transition-colors" to="/politica">Medidas de Segurança</Link>
            <a className="hover:text-white transition-colors" href="/sitemap.xml">Sitemap</a>
          </nav>
        </div>
      </div>
    </footer>
  );
}
